
export class AfterOpr {
    intercept(result:any, pConfig:any, input:any){
        let Util = pConfig.Util;
        let rtResult = [];
        let output;
        let params;
        let isPassthrough;
        let processor:string;
        if(pConfig.output)
            output = pConfig.output;
        if(output){
            params = output.params;
            processor = output.processor;
            isPassthrough = output.isPassthrough;            
            if(input.select){
                if(!params)
                    params = [];
                let selects = input.select.split(',');
                selects.forEach((item:any)=>{
                    let found = params.find((ele:any)=>ele.source === item);
                    if(!found)
                        params.push({source: item, target: item});
                });
            }
            isPassthrough = !params || params.length === 0;
        }
        if(params && params.length > 0){
            this.doItems(result, params, rtResult, input, processor, isPassthrough, Util);
            if(output && output.params){
                delete output.params;
            }
            return rtResult;
        }else{
            this.doItems(result, null, rtResult, input, processor, isPassthrough, Util);
            return rtResult;                
        }
    }
    private doItems(result:any, params:any, rtResult:any, input:any, processor:any, isPassthrough, Util:any){
        if(Array.isArray(result)){
            let rtElemSet;
            if(!isPassthrough && params){
                rtElemSet = params.filter((elem:any)=>{
                    if(elem.type === 'rowId')
                        elem.source = 'rowId';     
                    else if(elem.source === 'rowId')
                        elem.source = '__name__';
                    else if(elem.source === '__name__')
                        elem.target = 'rowId';
                    let foundIndex = result.findIndex((item:any)=> item[elem.source] !== undefined && item[elem.source] !== null && !elem.mask);                                                                           
                    if(foundIndex > -1)
                        return elem;
                });  
            }           
            result.forEach((item:any)=>{
                if(item.clientId)
                    delete item.clientId;
                let rItem:any = {};                 
                this.doChildItems(rtElemSet, item, rItem, Util);
                if(processor){
                    processor.doProcess(item, rItem, input);
                }
                if(!Util.isEmptyObject(rItem))
                    rtResult.push(rItem);
                else if(isPassthrough){                                        
                    rtResult.push(item);
                }
            });
        }else{
            let rst:any = {};
            if(result.opr === 'post'){
                rst.message = "Data Added";
                rst.status = 0;
                rst.id = result.id;
            }else if(result.opr === 'put'){
                rst.message = "Data Changed";
                rst.status = 0;
            }else if(result.opr === 'delete'){
                rst.message = "Data Removed";
                rst.status = 0;
            }
            let item:any = {};            
            this.doChildItems(params, item, rst, Util);
            if(processor){
                processor.doProcess(item, rst, input);
            }
            rtResult.push(rst);
        }
    }
    private doChildItems(rtElemSet:any, item:any, rst:any, Util:any){        
        if(rtElemSet){
            rtElemSet.forEach((rtElem)=>{
                let type = rtElem.type;
                let data = item[rtElem.source];
                /*if(typeof data !== 'number' && !data){
                    data = rtElem['default-value'];
                }*/
                if(data && data.toDate){
                    data = data.toDate();
                    type = 'date';
                }
                let format = rtElem.format;
                if(type === 'date'){
                    if(!format)
                        format = 'yyyy-MM-dd'
                        data = Util.getFormattedDateTime(data, format);
                    format = null;
                }
                if(type === 'file'){
                    if(format === 'binary2Base64')
                        data = Util.binary2Base64(item[rtElem.source]);
                    else if(format === 'base642Binary')
                        data = Util.base642Binary(item[rtElem.source]);
                }               
                rst[rtElem.target] = data;
            });
             
        }      
    }    
}
